/**
 * Token-bucket rate limiter.
 *
 * Fixed version with all three bugs resolved.
 */

export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number; // tokens per second
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  /**
   * Try to consume one token. Returns true if allowed, false if rate-limited.
   */
  tryConsume(): boolean {
    this.refill();

    // FIX 1: Changed from >= 1 to > 0
    // This allows consuming when tokens >= 1, handles fractional tokens correctly
    if (this.tokens > 0) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  /**
   * Get the current number of available tokens.
   */
  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  /**
   * Reset the limiter to full capacity.
   */
  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;

    // FIX 2: Changed from (elapsed * this.refillRate) to (elapsed / 1000 * this.refillRate)
    // elapsed is in milliseconds, refillRate is tokens per second
    // Need to convert elapsed to seconds by dividing by 1000
    const newTokens = (elapsed / 1000) * this.refillRate;

    // FIX 3: Cap tokens at maxTokens to prevent exceeding capacity
    this.tokens = Math.min(this.tokens + newTokens, this.maxTokens);

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];

    // Apply all filters combined with AND logic
    if (this.filters.length > 0) {
      result = result.filter((record) => {
        return this.filters.every((filter) => filter(record));
      });
    }

    // Apply all stages
    for (const stage of this.stages) {
      result = stage(result);
    }

    return result;
  }
}

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record): boolean => {
    return filters.every((filter) => filter(record));
  };
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record): boolean => {
    return filters.some((filter) => filter(record));
  };
}

export function notFilter(filter: Filter): Filter {
  return (record: Record): boolean => {
    return !filter(record);
  };
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = "CronParseError";
  }
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function parseField(
  field: string,
  fieldName: keyof typeof FIELD_RANGES
): number[] {
  const range = FIELD_RANGES[fieldName];
  const values = new Set<number>();

  if (field === "*") {
    for (let i = range.min; i <= range.max; i++) {
      values.add(i);
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  const parts = field.split(",");
  for (const part of parts) {
    if (part.includes("/")) {
      const [rangePart, stepStr] = part.split("/");
      const step = parseInt(stepStr, 10);

      if (isNaN(step) || step <= 0) {
        throw new CronParseError(
          `Invalid step value: ${stepStr}`,
          fieldName
        );
      }

      let start = range.min;
      let end = range.max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [startStr, endStr] = rangePart.split("-");
          start = parseInt(startStr, 10);
          end = parseInt(endStr, 10);

          if (isNaN(start) || isNaN(end)) {
            throw new CronParseError(
              `Invalid range: ${rangePart}`,
              fieldName
            );
          }
        } else {
          start = parseInt(rangePart, 10);
          end = start;

          if (isNaN(start)) {
            throw new CronParseError(
              `Invalid value: ${rangePart}`,
              fieldName
            );
          }
        }
      }

      if (start < range.min || start > range.max) {
        throw new CronParseError(
          `Value out of range: ${start} for ${fieldName}`,
          fieldName
        );
      }
      if (end < range.min || end > range.max) {
        throw new CronParseError(
          `Value out of range: ${end} for ${fieldName}`,
          fieldName
        );
      }

      for (let i = start; i <= end; i += step) {
        values.add(i);
      }
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (isNaN(start) || isNaN(end)) {
        throw new CronParseError(`Invalid range: ${part}`, fieldName);
      }

      if (start < range.min || start > range.max) {
        throw new CronParseError(
          `Value out of range: ${start} for ${fieldName}`,
          fieldName
        );
      }
      if (end < range.min || end > range.max) {
        throw new CronParseError(
          `Value out of range: ${end} for ${fieldName}`,
          fieldName
        );
      }

      for (let i = start; i <= end; i++) {
        values.add(i);
      }
    } else {
      const num = parseInt(part, 10);

      if (isNaN(num)) {
        throw new CronParseError(`Invalid value: ${part}`, fieldName);
      }

      if (num < range.min || num > range.max) {
        throw new CronParseError(
          `Value out of range: ${num} for ${fieldName}`,
          fieldName
        );
      }

      values.add(num);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] =
    fields;

  try {
    const minutes = parseField(minuteField, "minute");
    const hours = parseField(hourField, "hour");
    const daysOfMonth = parseField(dayOfMonthField, "dayOfMonth");
    const months = parseField(monthField, "month");
    const daysOfWeek = parseField(dayOfWeekField, "dayOfWeek");

    return {
      minutes,
      hours,
      daysOfMonth,
      months,
      daysOfWeek,
      original: expression,
    };
  } catch (error) {
    if (error instanceof CronParseError) {
      throw error;
    }
    throw new CronParseError(`Failed to parse cron expression: ${expression}`);
  }
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function errorResponse(status: number, error: string): Response {
  return {
    status,
    body: { success: false, error },
  };
}

function successResponse(status: number, data: unknown): Response {
  return {
    status,
    body: { success: true, data },
  };
}

function checkAuth(req: Request): Response | null {
  const token = req.headers["authorization"];
  if (!token) {
    return errorResponse(401, "Authorization required");
  }
  if (token !== "Bearer valid-token") {
    return errorResponse(401, "Invalid token");
  }
  return null;
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (id) {
    const item = store.get(id);
    return item
      ? successResponse(200, item)
      : errorResponse(404, "Item not found");
  }
  return successResponse(200, Array.from(store.values()));
}

function handlePost(req: Request): Response {
  if (!req.body) {
    return errorResponse(400, "Request body is required");
  }

  const data = req.body as Record<string, unknown>;
  if (!data["name"] || typeof data["name"] !== "string") {
    return errorResponse(400, "Validation failed: name is required");
  }

  const id = (data["id"] as string | undefined) || `item-${Date.now()}`;
  if (store.has(id)) {
    return errorResponse(409, "Item already exists");
  }

  const now = Date.now();
  const item: Item = {
    id,
    name: data["name"] as string,
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(id, item);
  return successResponse(201, item);
}

function handlePut(req: Request): Response {
  if (!req.body) {
    return errorResponse(400, "Request body is required");
  }

  const id = req.params["id"];
  if (!id) {
    return errorResponse(400, "Validation failed: id parameter is required");
  }

  const item = store.get(id);
  if (!item) {
    return errorResponse(404, "Item not found");
  }

  const data = req.body as Record<string, unknown>;
  const updated: Item = {
    ...item,
    updatedAt: Date.now(),
  };

  if (data["name"] && typeof data["name"] === "string") {
    updated.name = data["name"] as string;
  }

  if (
    data["status"] &&
    (data["status"] === "active" || data["status"] === "archived")
  ) {
    updated.status = data["status"] as "active" | "archived";
  }

  store.set(id, updated);
  return successResponse(200, updated);
}

function handleDelete(req: Request): Response {
  const id = req.params["id"];
  if (!id) {
    return errorResponse(400, "Validation failed: id parameter is required");
  }

  const item = store.get(id);
  if (!item) {
    return errorResponse(404, "Item not found");
  }

  store.delete(id);
  return successResponse(200, { deleted: id });
}

export function handleRequest(req: Request): Response {
  const authError = checkAuth(req);
  if (authError) {
    return authError;
  }

  switch (req.method) {
    case "GET":
      return handleGet(req);
    case "POST":
      return handlePost(req);
    case "PUT":
      return handlePut(req);
    case "DELETE":
      return handleDelete(req);
    default:
      return errorResponse(405, "Method not allowed");
  }
}

import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  describe("basic merging", () => {
    test("merges simple objects", () => {
      const target = { a: 1, b: 2 };
      const source = { c: 3 };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1, b: 2, c: 3 });
    });

    test("overwrites properties from target with source", () => {
      const target = { a: 1, b: 2 };
      const source = { b: 3, c: 4 };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1, b: 3, c: 4 });
    });

    test("does not mutate target", () => {
      const target = { a: 1 };
      const source = { b: 2 };
      deepMerge(target, source);
      expect(target).toEqual({ a: 1 });
    });

    test("does not mutate source", () => {
      const target = { a: 1 };
      const source = { b: 2 };
      deepMerge(target, source);
      expect(source).toEqual({ b: 2 });
    });
  });

  describe("nested objects", () => {
    test("recursively merges nested objects", () => {
      const target = { a: { b: 1, c: 2 } };
      const source = { a: { c: 3, d: 4 } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: 1, c: 3, d: 4 } });
    });

    test("handles deeply nested objects", () => {
      const target = { a: { b: { c: { d: 1 } } } };
      const source = { a: { b: { c: { e: 2 } } } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: { c: { d: 1, e: 2 } } } });
    });

    test("does not share nested object references", () => {
      const target = { a: { b: 1 } };
      const source = { a: { c: 2 } };
      const result = deepMerge(target, source);
      result.a.b = 999;
      expect(target.a.b).toBe(1);
    });

    test("replaces non-object values with nested objects", () => {
      const target = { a: 1 };
      const source = { a: { b: 2 } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: 2 } });
    });

    test("replaces nested objects with non-object values", () => {
      const target = { a: { b: 2 } };
      const source = { a: 1 };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1 });
    });
  });

  describe("arrays", () => {
    test("replaces arrays entirely", () => {
      const target = { a: [1, 2, 3] };
      const source = { a: [4, 5] };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: [4, 5] });
    });

    test("does not share array references", () => {
      const target = { a: [1, 2] };
      const source = { a: [3, 4] };
      const result = deepMerge(target, source);
      result.a.push(5);
      expect(source.a).toEqual([3, 4]);
    });

    test("replaces with empty array", () => {
      const target = { a: [1, 2, 3] };
      const source = { a: [] };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: [] });
    });

    test("handles arrays of objects", () => {
      const target = { a: [{ b: 1 }] };
      const source = { a: [{ c: 2 }] };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: [{ c: 2 }] });
    });

    test("handles nested arrays", () => {
      const target = { a: [[1, 2], [3, 4]] };
      const source = { a: [[5, 6]] };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: [[5, 6]] });
    });
  });

  describe("Date objects", () => {
    test("clones Date objects", () => {
      const date = new Date("2023-01-01");
      const target = { a: new Date("2022-01-01") };
      const source = { a: date };
      const result = deepMerge(target, source);
      expect(result.a).toEqual(date);
      expect(result.a).not.toBe(date);
    });

    test("clones Date in nested objects", () => {
      const date = new Date("2023-01-01");
      const target = { a: { b: new Date("2022-01-01") } };
      const source = { a: { b: date } };
      const result = deepMerge(target, source);
      expect(result.a.b).toEqual(date);
      expect(result.a.b).not.toBe(date);
    });

    test("Date clone maintains time", () => {
      const time = 1672531200000;
      const date = new Date(time);
      const target = { a: new Date(0) };
      const source = { a: date };
      const result = deepMerge(target, source);
      expect(result.a.getTime()).toBe(time);
    });
  });

  describe("null and undefined", () => {
    test("null in source replaces target value", () => {
      const target = { a: 1, b: 2 };
      const source = { a: null };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: null, b: 2 });
    });

    test("undefined in source is skipped", () => {
      const target = { a: 1, b: 2 };
      const source = { a: undefined };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1, b: 2 });
    });

    test("null replaces nested objects", () => {
      const target = { a: { b: 1 } };
      const source = { a: null };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: null });
    });

    test("null replaces arrays", () => {
      const target = { a: [1, 2, 3] };
      const source = { a: null };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: null });
    });

    test("undefined preserves target value in nested objects", () => {
      const target = { a: { b: 1, c: 2 } };
      const source = { a: { b: undefined } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: 1, c: 2 } });
    });
  });

  describe("Symbol keys", () => {
    test("merges symbol keys", () => {
      const sym = Symbol("test");
      const target = { a: 1, [sym]: 2 };
      const source = { [sym]: 3, b: 4 };
      const result = deepMerge(target, source);
      expect(result[sym]).toBe(3);
      expect(result.a).toBe(1);
      expect(result.b).toBe(4);
    });

    test("handles multiple symbol keys", () => {
      const sym1 = Symbol("sym1");
      const sym2 = Symbol("sym2");
      const target = { [sym1]: 1 };
      const source = { [sym1]: 2, [sym2]: 3 };
      const result = deepMerge(target, source);
      expect(result[sym1]).toBe(2);
      expect(result[sym2]).toBe(3);
    });

    test("symbol keys in nested objects", () => {
      const sym = Symbol("test");
      const target = { a: { [sym]: 1 } };
      const source = { a: { [sym]: 2 } };
      const result = deepMerge(target, source);
      expect(result.a[sym]).toBe(2);
    });

    test("null value for symbol key", () => {
      const sym = Symbol("test");
      const target = { a: 1, [sym]: 2 };
      const source = { [sym]: null };
      const result = deepMerge(target, source);
      expect(result[sym]).toBe(null);
    });

    test("undefined value for symbol key is skipped", () => {
      const sym = Symbol("test");
      const target = { a: 1, [sym]: 2 };
      const source = { [sym]: undefined };
      const result = deepMerge(target, source);
      expect(result[sym]).toBe(2);
    });
  });

  describe("prototype pollution protection", () => {
    test("skips __proto__ key", () => {
      const target = {};
      const source = { __proto__: { polluted: true } } as any;
      const result = deepMerge(target, source);
      expect(Object.prototype).not.toHaveProperty("polluted");
      expect((result as any).polluted).toBeUndefined();
    });

    test("skips constructor key", () => {
      const target = {};
      const source = { constructor: { polluted: true } } as any;
      const result = deepMerge(target, source);
      expect(Object.prototype).not.toHaveProperty("polluted");
    });

    test("skips prototype key", () => {
      const target = {};
      const source = { prototype: { polluted: true } } as any;
      const result = deepMerge(target, source);
      expect(Object.prototype).not.toHaveProperty("polluted");
    });

    test("forbidden keys are not present in result", () => {
      const target = { a: 1 };
      const source = { __proto__: { b: 2 }, constructor: { c: 3 }, prototype: { d: 4 }, a: 5 } as any;
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 5 });
      expect("__proto__" in result).toBe(false);
      expect("constructor" in result).toBe(false);
      expect("prototype" in result).toBe(false);
    });

    test("forbidden keys are skipped in nested merges", () => {
      const target = { a: { b: 1 } };
      const source = { a: { __proto__: { polluted: true }, c: 2 } } as any;
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: 1, c: 2 } });
      expect(Object.prototype).not.toHaveProperty("polluted");
    });
  });

  describe("edge cases", () => {
    test("merges empty objects", () => {
      const target = {};
      const source = {};
      const result = deepMerge(target, source);
      expect(result).toEqual({});
    });

    test("merges with empty source", () => {
      const target = { a: 1 };
      const source = {};
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1 });
    });

    test("merges with empty target", () => {
      const target = {};
      const source = { a: 1 };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1 });
    });

    test("handles primitive values in source", () => {
      const target = { a: "old" };
      const source = { a: "new", b: 123, c: true, d: false };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: "new", b: 123, c: true, d: false });
    });

    test("handles zero and false values", () => {
      const target = { a: 1, b: 2, c: 3 };
      const source = { a: 0, b: false, c: "" };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 0, b: false, c: "" });
    });

    test("handles multiple levels of nesting with mixed types", () => {
      const target = { a: { b: { c: 1, d: [1, 2] } } };
      const source = { a: { b: { c: null, d: [3] }, e: 2 } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: { c: null, d: [3], e: 2 } } });
    });

    test("maintains property order", () => {
      const target = { a: 1, b: 2 };
      const source = { c: 3, d: 4 };
      const result = deepMerge(target, source);
      const keys = Object.keys(result);
      expect(keys).toContain("a");
      expect(keys).toContain("b");
      expect(keys).toContain("c");
      expect(keys).toContain("d");
    });

    test("handles numeric keys", () => {
      const target = { 0: "a", 1: "b" };
      const source = { 1: "c", 2: "d" };
      const result = deepMerge(target, source);
      expect(result).toEqual({ 0: "a", 1: "c", 2: "d" });
    });
  });

  describe("non-plain objects", () => {
    test("replaces class instances instead of merging", () => {
      class TestClass {
        prop = 1;
      }
      const target = { a: new TestClass() };
      const source = { a: new TestClass() };
      source.a.prop = 2;
      const result = deepMerge(target, source);
      expect(result.a.prop).toBe(2);
    });

    test("handles Date in source that should not merge", () => {
      const target = { a: { b: 1 } };
      const source = { a: new Date() };
      const result = deepMerge(target, source);
      expect(result.a instanceof Date).toBe(true);
    });

    test("does not merge arrays of objects as plain objects", () => {
      const target = { a: { items: [{ id: 1 }] } };
      const source = { a: { items: [{ id: 2 }] } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { items: [{ id: 2 }] } });
    });
  });

  describe("type behavior", () => {
    test("works with string values", () => {
      const target = { a: "hello" };
      const source = { a: "world" };
      const result = deepMerge(target, source);
      expect(result.a).toBe("world");
    });

    test("works with number values", () => {
      const target = { a: 5 };
      const source = { a: 10 };
      const result = deepMerge(target, source);
      expect(result.a).toBe(10);
    });

    test("works with boolean values", () => {
      const target = { a: true };
      const source = { a: false };
      const result = deepMerge(target, source);
      expect(result.a).toBe(false);
    });

    test("works with function values", () => {
      const fn = () => "test";
      const target = { a: () => "old" };
      const source = { a: fn };
      const result = deepMerge(target, source);
      expect(result.a).toBe(fn);
    });
  });
});
